INSERT INTO vault VALUES(202,'seeds','seed-1772282384-qkkk','/Users/jennwoeiloh/.openclaw/workspace/data/seeds.jsonl','','templates/copy','dreami','copy','⚡ THE ANGLE: Science-backed nutrition that doesn''t taste like cardboard.\n\n💪 Burned through another 5am spin class and hitting that 2pm energy crash? Your body deserves better than sugar. Dr Stan uses clinical-grade protein (20g) with clean, science-backed ingredients — no artificial junk, just nutrition that your doctor would actually prescribe.\n\nPerfect for:\n- Post-workout recovery\n- Between-meal hunger strikes\n- Busy professionals who need brain fuel, not sugar spikes\n\n🎯 CTA: Tap the link to order doctor-approved fuel. Your gains will thank you.\n\n#DrStanProteinBar #ScienceBased #CleanEating #FitnessCommunity #MealPrepFriendly #ProteinLover #SingaporeFitness #MalaysiaWorkout #CleanLabel #HealthySnacking #WorkoutFuel #ProteinBar #FitnessMotivation','{"tags": ["protein-bar", "science-based", "fitness-millennial", "clean-label"], "performance": {"ctr": null, "roas": null, "impressions": null, "engagement": null}, "status": "draft", "channel": null}',1772282385019,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(203,'seeds','seed-1772282396-4lit','/Users/jennwoeiloh/.openclaw/workspace/data/seeds.jsonl','','templates/copy','dreami','copy','🏃 THE ANGLE: Finally, protein bars you''ll actually enjoy.\n\nBetween 9am meetings, lunch with clients, and dodging emails until 8pm, who has time for fancy meal prep? Dr Stan hits the sweet spot between "I''m too busy to care" and "I actually want to eat something that fuels my ambition."\n\n🧠 20g protein. 0 artificial ingredients. Zero excuses. Perfect for:\n- Gym bag snacks that don''t crumble in your pocket\n- Desk fuel that keeps you sharp, not jittery\n- Post-gym recovery that doesn''t require 10 minutes to eat\n\n💡 Trust the doc. Your busy life deserves something that works as hard as you do.\n\n🎯 CTA: Grab your stash now. More wins, less prep.\nTap the link! 👇\n\n#DrStan #BusyPro #HealthySnacks #GymBagEssentials #WorkSmartLiveBetter #ProteinBar #CleanLabel #SingaporeProfessional #MalaysiaBusy #MealOnTheGo #FitnessProfessional #HealthyLiving #CorporateWellness #WorkLifeBalance','{"tags": ["protein-bar", "busy-professional", "gym-bag-snack", "healthy-workplace"], "performance": {"ctr": null, "roas": null, "impressions": null, "engagement": null}, "status": "draft", "channel": null}',1772282396757,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(204,'seeds','seed-1772282425-uwux','/Users/jennwoeiloh/.openclaw/workspace/data/seeds.jsonl','','templates/copy','dreami','copy','🤔 THE ANGLE: Why protein bars taste like sadness and why we changed that.\n\nLet''s be real: most protein bars taste like chalk chewed by a disappointed dentist. You power through them because protein is expensive and guilt trips you hard. Dr Stan? We''re breaking up with the cardboard era.\n\n⚖️ Clean protein. Real taste. Doctor-approved (yes, we have the degrees). Perfect for:\n- Hitting macros without the mental groan\n- Protein goals that actually align with your taste buds\n- Active lifestyles that deserve better than "it''s protein so it''s fine"\n\n✨ Not your doctor''s prescription for bland nutrition. Just good stuff.\n\n🎯 CTA: Level up your snack game. Your tastebuds and your gains will both thank you.\nShop now: link in bio 👇\n\n#DrStanProteinBar #SayNoToCardboard #ProteinGoals #FitnessJourney #CleanLabel #HealthySnacking #ProteinBarLovers #SingaporeFitness #MalaysiaHealth #EatRealFood #FitnessMotivation #ProteinBarReview #RealFoodRealResults','{"tags": ["protein-bar", "irreverent", "hook-based", "breakup-angle"], "performance": {"ctr": null, "roas": null, "impressions": null, "engagement": null}, "status": "draft", "channel": null}',1772282426035,'2026-03-06 11:34:28');
