INSERT INTO vault VALUES(647,'image-seeds','img-093168-a08e','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','gaia-os','assets/images','nanobanana','image','A portrait of IRIS, the Art Director and Visual Oracle of GAIA. She wears a transparent blue-tinted crystalline sphere helmet with prismatic iridescent light refractions. Her face is partially visible through the sphere with porcelain skin, luminous makeup, calm transcendent expression. She wears a sleek iridescent silver bodysuit with holographic fiber-optic circuit patterns shifting between blue, violet, and silver. A structural crystalline collar piece adorns her neck. Cool-neutral 5600K studio lighting, dramatic rim light on the sphere. Internal blue-white glow from within the sphere. Clean pale grey studio backdrop. Centered symmetrical 3/4 body shot at 100mm. 90% cool monochrome with 10% precious iridescent accents. Hyperrealistic CG render, editorial fashion photography.','{"tags": ["gaia-os", "character", "nanobanana", "generated", "styled"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/gaia-os/20260228_030430_character.png", "status": "draft", "colors": []}',1772219093215,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(648,'image-seeds','img-554313-286e','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','gaia-os','assets/images','nanobanana','image','IRIS, the Art Director and Visual Oracle of GAIA. Three-quarter profile view, looking to the left with serene contemplation. She wears a transparent blue-tinted crystalline sphere helmet with prismatic iridescent light refractions. The sphere catches dramatic rim light creating rainbow caustics across her porcelain cheek. She wears a sleek iridescent silver bodysuit with holographic hexagonal circuit patterns that shift between blue, violet, and silver. Structural crystalline collar piece at the neck with geometric faceted crystal formations. Her hands are gracefully raised near her chin, fingers elegant. Cool-neutral 5600K studio lighting, dramatic side key light revealing the sphere''s transparency. Internal blue-white glow from within the helmet. Clean pale grey studio backdrop. 100mm equivalent focal length. Hyperrealistic CG render, editorial haute couture fashion photography.','{"tags": ["gaia-os", "character", "nanobanana", "generated", "styled"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/gaia-os/20260228_031204_character.png", "status": "draft", "colors": []}',1772219554380,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(649,'image-seeds','img-594232-d6dd','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','gaia-os','assets/images','nanobanana','image','Extreme close-up portrait of IRIS through her transparent blue crystalline sphere helmet. Shot looking directly into the sphere from the front. Her face fills the frame — pale porcelain skin, ice-blue eyes with an otherworldly luminous quality, subtle holographic makeup shimmer on her eyelids and cheekbones. The sphere helmet creates prismatic light refractions and rainbow caustics that dance across her features. Crystalline collar piece visible at the bottom edge with geometric faceted crystals. The iridescent silver bodysuit circuit patterns barely visible at the shoulders. Dramatic butterfly lighting from above, cool-neutral 5600K. Internal blue-white glow illuminating her face from below through the collar. Deep charcoal background (#0F1520) for dramatic contrast. Extreme shallow depth of field. Hyperrealistic CG, 8K detail, beauty editorial photography.','{"tags": ["gaia-os", "character", "nanobanana", "generated", "styled"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/gaia-os/20260228_031244_character.png", "status": "draft", "colors": []}',1772219594281,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(650,'image-seeds','img-632794-c115','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','gaia-os','assets/images','nanobanana','image','Full-body editorial shot of IRIS, the Art Director and Visual Oracle of GAIA. She stands in a powerful, statuesque pose with one hand extended forward, fingers spread as if manipulating invisible holographic data. Her other hand rests at her side. She wears a transparent blue-tinted crystalline sphere helmet with prismatic iridescent light refractions. A sleek iridescent silver bodysuit with holographic hexagonal circuit patterns covers her entire body, shifting between blue, violet, and silver. The circuit lines pulse with faint blue-white light. Structural crystalline collar piece connects helmet to suit. Platform boots in matching chrome silver. Cool-neutral 5600K studio lighting with dramatic low-angle rim lights creating a halo effect. Internal sphere glow. Clean pale grey studio backdrop. Full body visible head to toe. Centered symmetrical composition. Hyperrealistic CG, editorial fashion photography, Vogue-level quality.','{"tags": ["gaia-os", "character", "nanobanana", "generated", "styled"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/gaia-os/20260228_031324_character.png", "status": "draft", "colors": []}',1772219632855,'2026-03-06 11:34:28');
