INSERT INTO vault VALUES(658,'image-seeds','img-545280-6589','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','pinxin-vegan','assets/images','nanobanana','image','Commercial product photography of Pinxin Vegan plant milk carton on rustic wooden table. Fresh natural setting with green leaves and wooden bowl. Soft morning light streaming through window. Clean minimalist composition, soft shadows, appetizing health-focused aesthetic. Vibrant green and gold tones matching vegan brand colors. Professional studio lighting, shallow depth of field, photorealistic 8K detail.','{"tags": ["pinxin-vegan", "product", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/pinxin-vegan/20260228_202515_product.png", "status": "draft", "colors": []}',1772281545336,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(659,'image-seeds','img-930024-4771','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','gaia-eats','assets/images','nanobanana','image','Professional food photography of colorful healthy Buddha bowl. Base of fluffy golden quinoa with roasted sweet potato cubes (vibrant orange with char marks), crispy white chickpeas, fresh cucumber slices, red cherry tomatoes, golden marinated tofu cubes. Drizzled with creamy peanut-sesame dressing creating beautiful ribbons. Garnished with fresh Thai basil and coriander leaves. Served in pastel ceramic bowl. Shot from 45-degree aerial angle, natural morning light streaming from side, shallow depth of field, commercial food photography style, vibrant colors, appetizing and Instagram-worthy. Clean background with soft shadows. 8K detail, photorealistic.','{"tags": ["gaia-eats", "social", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/gaia-eats/20260228_204820_social.png", "status": "draft", "colors": []}',1772282930077,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(660,'image-seeds','img-411386-3fd7','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','pinxin-vegan','assets/images','nanobanana','image','Pinxin Vegan plant milk product photography. Clean cream background, soft natural lighting from upper left. Plant milk carton/bottle centered, subtle shadow beneath. Brand colors: fresh green (#4CAF50), earthy brown (#8D6E63), cream (#F5F0EB). Bold, appetizing, proudly Malaysian vegan aesthetic. High-end e-commerce quality, 4K resolution.','{"tags": ["pinxin-vegan", "product", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/pinxin-vegan/20260228_230917_product.png", "status": "draft", "colors": []}',1772291411448,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(661,'image-seeds','img-525134-df7f','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Editorial food photography for MIRRA Instagram feed. Hero shot of Japanese Curry Katsu Bento: golden-brown crispy plant-based katsu cut in half, fluffy Japanese rice, rich golden curry sauce. Warm golden hour lighting, soft focus, film grain texture. Teal and rose accents against warm cream background. Sophisticated, calm, luxurious aesthetic. Minimalist Japanese plating on matte ceramic.','{"tags": ["mirra", "product", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260301_221450_product.png", "status": "draft", "colors": []}',1772374525185,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(662,'image-seeds','img-362197-6bf8','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Real food photography of a Japanese curry katsu bento box in a white compartment container, top-view angle. Crispy golden plant-based katsu with curry sauce, fluffy rice, colorful vegetable sides. Clean warm natural daylight. Salmon pink (#F7AB9F) background with cream (#FFF9EB) tones. Minimalist clean layout. White bento container. Fresh, appetizing, warm feminine aesthetic. No text overlay. Professional food photography style matching MIRRA meal delivery brand.','{"tags": ["mirra", "product", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260301_222838_product.png", "status": "draft", "colors": []}',1772375362248,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(663,'image-seeds','img-681801-e899','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Lifestyle photography for MIRRA Instagram feed (1080x1350, 4:5 ratio). Warm, feminine, clean aesthetic with salmon pink (#F7AB9F) and cream (#FFF9EB) color palette. SCENE: Woman (relaxed expression, warm tones) holding a MIRRA bento box, sitting at a cafe table with plant in background. Soft golden hour lighting from window, natural shadows. FRAMING: Candid lifestyle shot - not posed, just enjoying a meal. Warm, inviting, authentic. BACKGROUND: Salmon pink organic blob shapes creating soft gradient background (#F7AB9F to #FFF9EB). No harsh edges. TEXT ELEMENTS: Meals That Make You Feel Good in elegant serif font on soft white card. Food sedap, but healthy in warm BM font. BRAND STYLING: White ceramic bento, subtle food photography style (real ingredients visible). No editorial beauty photography or film grain. Lighting: Clean natural daylight, slightly warm, no heavy shadows - food looks fresh and appetizing. TONE: Relatable, warm, confident - like a friend who eats well. Not cold, not corporate. COLOUR PALETTE: Primary - Salmon pink #F7AB9F, Secondary - Cream #FFF9EB, Accent - Warm gold (#FFD700 for minimal use).','{"tags": ["mirra", "lifestyle", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260301_235714_lifestyle.png", "status": "draft", "colors": []}',1772380681852,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(664,'image-seeds','img-005810-4fd3','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Social media ad design, split comparison layout. Left side: salmon pink background (#F7AB9F), bold black serif headline "This", a plate of regular Malaysian fried rice with egg on top, dark calorie badge showing "900 kcal". Right side: cream background (#FFF9EB), bold black serif headline "or That", a white compartmented MIRRA bento box top-view showing pink rice with lettuce, lemon mushroom chicken in sauce, stir-fried vegetables with broccoli and carrots, and sesame eggplant — pink calorie badge showing "423 kcal". Thin dashed vertical divider line in center. "MIRRA" black serif logo top-right corner. Bottom text bar: "Same delicious local flavours, no compromises" in black serif. Small circular "Nutritionist Designed" badge near the bento. This is a DESIGNED AD LAYOUT composite, not a raw photograph. Clean, professional, warm feminine aesthetic.','{"tags": ["mirra", "social", "nanobanana", "generated", "mofu"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260302_024941_social.png", "status": "draft", "colors": []}',1772391005873,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(665,'image-seeds','img-160010-d8e7','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Lifestyle product photography of a MIRRA healthy bento box meal on a light wooden desk. White 4-compartment bento container with vibrant Malaysian food — pink beetroot rice with green lettuce, golden lemon mushroom chicken in sauce, colorful stir-fried vegetables, and small dipping sauces. Next to the bento: a glass of iced lemon tea, a white ceramic mug with wooden utensils, a linen napkin, and a notebook. Clean natural daylight from the left, slightly warm, soft shadows. Shot from above at 45 degree angle. Warm, inviting, feminine.','{"tags": ["mirra", "lifestyle", "nanobanana", "generated", "mofu"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260302_025206_lifestyle.png", "status": "draft", "colors": []}',1772391160063,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(666,'image-seeds','img-259941-9d31','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Social media ad design for Instagram feed (1:1). Solid salmon pink background (#F7AB9F). Bold black serif headline at top: "Counting Calories at Work?" followed by smaller serif subtitle "We Did It. Delicious bentos under 500 kcal done\!" Black serif "MIRRA" logo in top-right corner. Below the text: a 3x3 grid of 9 top-view photographs of different healthy bento boxes in white compartmented containers. Each bento shows a different colorful Malaysian meal — pink rice, pasta, wraps, curries, vegetables. Below each bento: meal name in small black serif text and calorie count in parentheses (e.g. "Nasi Lemak (423kcal)"). This is a DESIGNED AD LAYOUT with real food photography composited onto a solid colored background, not a raw photograph.','{"tags": ["mirra", "social", "nanobanana", "generated", "mofu"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260302_025329_social.png", "status": "draft", "colors": []}',1772391259993,'2026-03-06 11:34:28');
