INSERT INTO vault VALUES(759,'image-seeds','img-397188-8ce6','/Users/jennwoeiloh/.openclaw/workspace/rag/image-seed-bank.jsonl','mirra','assets/images','nanobanana','image','Split comparison ad for MIRRA bento meals vs unhealthy takeout. LEFT side: Unhealthy takeout from mamak restaurant - greasy nasi lemak, oily fried rice, sugary drinks - messy, high calories (800+), expensive, and poor nutrition. RIGHT side: MIRRA healthy bento box - top-view view of nutritious bento with vibrant vegetables, protein, grains in elegant white container with pink logo. SHOW ON RIGHT: Nutritionist-designed badge, 500 calories, RM18 (vs RM25 takeout), healthy ingredients. Background: soft pink (#F7AB9F) and cream (#FFF9EB) with organic blob shapes. Lighting: clean natural daylight. Photography style: real food photography with fresh, appetizing appearance. Split layout with thick dividing line, MIRRA text on right. Visual hierarchy: 1) Unhealthy takeout label on left, 2) MIRRA bento label on right, 3) Calorie comparison badges (800+ vs 500 kcal), 4) Savings badge (Save RM7). No text or extraneous UI.','{"tags": ["mirra", "product", "nanobanana", "generated"], "file_path": "/Users/jennwoeiloh/.openclaw/workspace/data/images/mirra/20260302_202550_product.png", "status": "draft", "colors": []}',1772454397245,'2026-03-06 11:34:28');
