INSERT INTO vault VALUES(1045,'patterns','wp-001','/Users/jennwoeiloh/.openclaw/workspace/data/winning-patterns.jsonl','','operations/patterns','athena','pattern','Question hooks starting with ''Did you know'' drive high engagement. Recommendation: Use ''Did you know X can be Y?'' format for food discovery hooks','{"channels": ["tiktok"], "confidence": "high", "evidence": {"winning_example": "Did you know rendang can be vegan?", "ctr": 3.2, "roas": 4.1, "engagement": 8.5}, "pattern_type": "hook_format"}',1739587200000,'2026-03-06 11:34:28');
INSERT INTO vault VALUES(1046,'patterns','wp-002','/Users/jennwoeiloh/.openclaw/workspace/data/winning-patterns.jsonl','','operations/patterns','athena','pattern','Heritage Malaysian dishes + plant-based twist resonates strongly. Recommendation: Lead with familiar Malaysian dishes, reveal plant-based twist','{"channels": ["tiktok", "ig"], "confidence": "high", "evidence": {"winning_examples": ["Vegan rendang", "Plant-based nasi lemak"], "top_ctr": 3.2, "top_roas": 4.1}, "pattern_type": "content_theme"}',1739587200000,'2026-03-06 11:34:28');
