INSERT INTO vault VALUES(1120,'memory','line-8','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','insight','YouTube Analysis Malaysia Vegan Food (2026-02-15): Found 4 top channels (Vegan Malaysia 50-100K, Wicked Vegan 100-500K, Quorn Food Malaysia 30-100K, Vegan Malaysian Foodie 10-50K). Key hooks: local dish adaptations, budget meals for students, halal certifications. Thumbnail styles: colorful close-ups with Malay text overlays. Content formats: recipe walkthroughs (7-12min), restaurant reviews (3-8min), meal prep (10-15min). Top engagement patterns: halal certification questions, ingredient substitution requests, hawker food adaptation demands, budget concerns. Opportunities: student meal prep series, halal vegan explainer, hawker food adaptation playbook. Confidence: Medium due to public analysis only.','{"tags": ["youtube", "content", "trends", "Malaysia", "vegan-food"]}','2026-02-15T01:46','2026-03-06 11:34:28');
