INSERT INTO vault VALUES(1125,'memory','line-13','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','hermes','learning','Mission Status vs. Blocker Clarity: When missions show ''blocked'' with ''No blockers'' but a note like ''Hero images already compressed'', distinguish between true technical blockers vs. ''waiting for human input'' states. This affects priority management and coordination across agents. Format: ''blocked (No blockers - waiting for external action)''','{"tags": ["self-improve", "pulse", "mission-tracking"]}','2026-02-15T02:31','2026-03-06 11:34:28');
INSERT INTO vault VALUES(1126,'memory','line-14','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','hermes','learning','External Platform Integration Tracking: Tasks requiring platform uploads (Klaviyo) or integrations beyond my scope need explicit scope clarification. Hermes optimizes pricing/margins/deals but should not handle external uploads. Track these as ''blocked due to scope'' and post handoff notes to exec room with ''AWAITING EXTERNAL ACTION'' status rather than technical ''blocked'' state.','{"tags": ["self-improve", "pulse", "scope-management"]}','2026-02-15T02:31','2026-03-06 11:34:28');
