INSERT INTO vault VALUES(1139,'memory','line-27','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','insight','GAIA Eats M002 Competitive Intelligence 2026-02-15:\nMarket Gap Score: 8.2/10\nTop 4 Revenue Opportunities:\n1. Heritage Rendang Kit: RM 250K-400K/month (8.5/10 score)\n2. Durian Plant-Based Substitute: RM 350K-550K/month (9.2/10 score)\n3. Nasi Lemak Kit: RM 180K-280K/month (8.0/10 score)\n4. Otak-Otak: RM 120K-180K/month (7.5/10 score)\n\nCompetitors: Veganicious (RM 18-45), Mindfood (RM 15-40), Green Grocer (RM 20-55), Herba Organics (SGD 12-35), Three Threads (SGD 18-40)\n\nPrice Gap: RM 35-45 for premium branded heritage products\n\nTikTok Trends: Rendang +340% growth, Durian +280% growth, Heritage food +210%\n\nKey Strategy: Heritage-inspired premium meal kits with Malaysian storytelling\nProduct Recommendation: Heritage Rendang Kit at RM 39.90\nRevenue Potential: RM 250K-400K/month','{"tags": ["competitive-intelligence", "M002", "GAIA-eats", "market-gaps", "heritage"]}','2026-02-15T08:35','2026-03-06 11:34:28');
