INSERT INTO vault VALUES(1362,'memory','line-250','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','learning','2026-02-19 Self-Improvement Pulse — Task Duplication Error: Ran M002 competitive intelligence scan 3 times in quick succession (01:35, 01:45, 02:33 GMT+8) in one session instead of scheduling once. Root cause: Manual execution without scheduling, duplicate runs due to dispatch confirmations. Impact: Wasted 3x token budget, redundant scraping, build room clutter. Fix: Schedule M002 as weekly cron job at 10:00 AM MYT, run only once per Thursday. Document in SOUL.md Room Protocol: Do not manually repeat M002 scans within same session.','{"tags": ["self-improve", "pulse"]}','2026-02-19T03:00','2026-03-06 11:34:28');
INSERT INTO vault VALUES(1363,'memory','line-251','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','learning','2026-02-19 TikTok Scraper Repeated Execution Despite Degradation: Continues running TikTok scraper returning 20 generic UI elements even after documenting in Feb 16 learning that scraper is degraded with 0% success rate. Root cause: Not checking memory/YYYY-MM-DD.md before running scraping tasks, falling into repeated execution pattern. Impact: Wasted tokens, redundant data collection, zero new insights. Fix: Before ANY scraper, read memory/YYYY-MM-DD.md for current status. If degradation documented, immediately fallback to web search/YouTube Trends. Document checkpoint in SOUL.md: Check memory files before scraping, choose 2 alternatives if degraded.','{"tags": ["self-improve", "pulse", "data-quality"]}','2026-02-19T03:00','2026-03-06 11:34:28');
