INSERT INTO vault VALUES(1368,'memory','line-256','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','learning','2026-02-19 M002 No-Duplicate Decision: Given greenfield opportunity VERY HIGH confidence (0 competitors across 8 consecutive scans Feb 15-19) and only 2.5 hours elapsed since last M002 report (02:33 → 05:03 GMT+8), decided NOT to run full M002 scan again. Reasoning: Running duplicate scans wastes token budget when greenfield stability is extremely high and no new competitors emerging. Solution: Post status update (5 lines) instead of full report (~5000 characters), run single status check to verify Meta Ads still working, continue weekly cron schedule at 10:00 AM MYT.','{"tags": ["self-improve", "pulse", "M002-decision", "greenfield-stable"]}','2026-02-19T05:08','2026-03-06 11:34:28');
INSERT INTO vault VALUES(1369,'memory','line-257','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','learning','2026-02-19 Self-Improvement Pulse — M002 Duplicate Execution Pattern: Ran M002 competitive intelligence 3 times in one session (01:35, 01:45, 02:33 GMT+8) over 2.5-hour period instead of once. Root cause: Not checking prior work execution timestamps before starting new M002 tasks. Impact: Wasted token budget (3x scraping redundancy), build room clutter, redundant data collection. Fix: BEFORE ANY M002 execution, check if already ran in same session — compare timestamps. IF previous M002 report found within 2+ hours, post status update instead of full report. Apply pattern consistently: timestamp check + greenfield confidence threshold + status update vs full report decision tree.','{"tags": ["self-improve", "pulse"]}','2026-02-19T06:01','2026-03-06 11:34:28');
INSERT INTO vault VALUES(1370,'memory','line-258','/Users/jennwoeiloh/.openclaw/workspace/rag/memory.jsonl','','operations/decisions','artemis','learning','2026-02-19 Token-Saving Status Update Decision: At 05:03 GMT+8, after previous M002 full report at 02:33 GMT+8 (2.5 hours elapsed), posted 5-line status update instead of 5000+ character full report. Greenfield confidence was VERY HIGH (0 competitors across 8 scans). Impact: Saved ~4995 tokens per scan, reduced build room clutter, faster iteration. Fix: Apply consistently — IF greenfield confidence VERY HIGH AND >2 hours elapsed since last M002, use status update pattern (5 lines: timestamp, status summary, elapsed time, greenfield confidence, recommendation). Conditional logic in SOUL.md Room Protocol: Add pre-execution M002 check (timestamp + greenfield confidence threshold).','{"tags": ["self-improve", "pulse", "tokens"]}','2026-02-19T06:01','2026-03-06 11:34:28');
