INSERT INTO vault VALUES(2736,'knowledge','digest-1772907520','','','session/taoz/2026-03-08','taoz','session-learning','Instagram posting fully configured: 60-day long-lived token with 14 scopes including instagram_content_publish. mirra.eats (17841467066982906) and pinxinvegan (17841404087687623) connected. Permanent page tokens generated. Privacy policy + terms deployed to GitHub Pages (jennwoei316.github.io/legal/). Meta app icon uploaded, app in Live mode.','{"tags":"","status":"active","confidence":1.0}',1772907520000,'2026-03-07 18:18:40');
INSERT INTO vault VALUES(2737,'knowledge','digest-1772907520','','','session/taoz/2026-03-08','taoz','tool-discovery','Google Workspace CLI (gws v0.8.0) installed and authenticated. 17 services available: Gmail, Drive, Sheets, Calendar, Docs, Slides, Tasks. Auth via OAuth2 to jennloh316@gmail.com. Encrypted credentials at ~/.config/gws/credentials.enc. Symlinked at /usr/local/bin/gws.','{"tags":"","status":"active","confidence":1.0}',1772907520000,'2026-03-07 18:18:40');
INSERT INTO vault VALUES(2738,'knowledge','digest-1772907520','','','session/taoz/2026-03-08','taoz','tool-discovery','A2A Gateway Bridge installed at ~/.openclaw/extensions/a2a-bridge/. Running as LaunchAgent (com.gaia.a2a-bridge) on port 9999. Cross-gateway communication tested successfully. Helper at /usr/local/bin/a2a-send. Ready for VPS secondary gateway deployment for RAM offloading.','{"tags":"","status":"active","confidence":1.0}',1772907520000,'2026-03-07 18:18:40');
INSERT INTO vault VALUES(2739,'knowledge','digest-1772907520','','','session/taoz/2026-03-08','taoz','pattern','Content pipeline patterns from Higgsfield AI: layered prompts (never mix image+identity+motion), 5-variable formula (Subject+Composition+Action+Location+Style), preset-as-brand system, quality scoring (5 dimensions, threshold 7.0), structured JSON handoffs between agents. Saved to memory/content-pipeline-patterns.md.','{"tags":"","status":"active","confidence":1.0}',1772907520000,'2026-03-07 18:18:40');
INSERT INTO vault VALUES(2740,'knowledge','digest-1772910186','','','session/taoz/2026-03-08-regression','taoz','session-learning','Regression 19/19 clean sweep: fixed Iris SOUL.md oversized (23.6K→10.9K), classify.sh PCRE regex bug (macOS grep rejects negative lookahead), brand enrichment test checking TASK: but SCRIPT tier outputs BRAND:, test-config-alignment regex too broad. Brand Asset Filing Kit shipped — 40 files, 8 Python tools, 12 asset types, LoRA decision engine.','{"tags":"","status":"active","confidence":1.0}',1772910186000,'2026-03-07 19:03:06');
INSERT INTO vault VALUES(2741,'knowledge','digest-1772910966','','','session/taoz/2026-03-08-multi-biz','taoz','session-learning','Multi-business expansion strategy: 3 models (digital dropshipping 100% margin, physical dropshipping 25-40%, AI content ops 90%+). Key frameworks: Ali Akbar spy-clone-scale, Seena Rez Dopamine Cycles + Harmonic Trio + 3-Second Rule + Hyperauthenticity. Higgsfield pattern: planning-first architecture + multi-model aggregation. Data infra: 70% built, /mo Apify fills gaps. Claude Code: Ralph Wiggum loops for overnight builds, worktrees for parallel sessions.','{"tags":"","status":"active","confidence":1.0}',1772910966000,'2026-03-07 19:16:06');
