INSERT INTO vault VALUES(2752,'knowledge','digest-1772987039','','','session/argus/2026-03-09','argus','bug','classify.sh routing bug: ''ad performance this week'' routes to hermes instead of athena. Line 155 pattern ''ads?.?performance.*(last|this|...|week)'' catches before line 260 athena pattern. Fix: reorder patterns or make hermes pattern more specific (require ''meta ads performance'').','{"tags":"","status":"active","confidence":1.0}',1772987039000,'2026-03-08 16:23:59');
INSERT INTO vault VALUES(2753,'knowledge','digest-1772987174','','','session/argus/2026-03-09','argus','pattern','KNOWLEDGE-SYNC.md contains SESSION SYNC section with daily Jenn-Claude Code conversation summary. This is the canonical source for understanding what''s being built. Taoz should read this first before any build task.','{"tags":"","status":"active","confidence":1.0}',1772987174000,'2026-03-08 16:26:14');
INSERT INTO vault VALUES(2754,'knowledge','digest-1772987511','','','session/argus/2026-03-09','argus','infrastructure','GAIA OS knowledge infrastructure: vault.db (2,753 entries), gaia.db (56 knowledge rows), 162 skills, 13 brands, 23 rooms, 9 daily logs. KNOWLEDGE-SYNC.md is the bridge between Claude Code Taoz and OpenClaw Taoz.','{"tags":"","status":"active","confidence":1.0}',1772987511000,'2026-03-08 16:31:51');
INSERT INTO vault VALUES(2755,'knowledge','digest-1772992651','','','session/argus/2026-03-09','argus','mission','JADE ORACLE mission launched: AI psychic reading business with 3 personas (Seraphina, Wei Lian, Luna), 6 products (-), QMDJ+Tarot+Astrology engine. Phase 1: D1 (brand copy) → Dreami, I1 (persona art) → Iris, T1 (reading pipeline) → Taoz.','{"tags":"","status":"active","confidence":1.0}',1772992651000,'2026-03-08 17:57:31');
INSERT INTO vault VALUES(2756,'knowledge','digest-1772992792','','','session/argus/2026-03-09','argus','bug','Nested regression dispatch loop: done-gate can create infinite ''Run regression testing for task: Run regression testing for task:...'' chains. This causes DONE BLOCKED loops. System should detect and break after 1 level of nesting.','{"tags":"","status":"active","confidence":1.0}',1772992792000,'2026-03-08 17:59:52');
INSERT INTO vault VALUES(2757,'knowledge','digest-1772992848','','','session/argus/2026-03-09','argus','bug','CONFIRMED: done-gate creates infinite nested regression dispatch loops. 4-level nesting observed. System needs recursion detection — max 1 level of ''Run regression testing for task:'' nesting allowed. Otherwise token waste and DONE BLOCKED loops occur.','{"tags":"","status":"active","confidence":1.0}',1772992848000,'2026-03-08 18:00:48');
INSERT INTO vault VALUES(2758,'knowledge','digest-1773027498','','','session/argus/2026-03-09','argus','session-learning','Jade Oracle psychic reading pipeline (Shopify webhook → reading → PDF) regression PASSED. Core components working: webhook handler, Western astrology + Tarot engines, PDF generator. Known gaps: email delivery placeholder, QMDJ visualization placeholder. 9/11 verification tests pass. Production-ready after SendGrid setup.','{"tags":"","status":"active","confidence":1.0}',1773027498000,'2026-03-09 03:38:18');
INSERT INTO vault VALUES(2759,'knowledge','digest-1773035361','','','session/argus/2026-03-09','argus','session-learning','Jade Oracle Shopify store BLOCKED: Domain thejadeoracle.com already owned by different business (oracle cards/tours in Albuquerque, NM). Taoz created all artifacts (products.json, configs, setup script) but cannot deploy. Requires human decision: new domain, domain acquisition, or subdomain strategy.','{"tags":"","status":"active","confidence":1.0}',1773035361000,'2026-03-09 05:49:21');
INSERT INTO vault VALUES(2760,'knowledge','digest-1773115970','','','session/argus/2026-03-10','argus','session-learning','Regression 15/19 PASS. 3 FAIL: main SOUL.md over 20K chars (21,621) causes gateway truncation, zenni-campaign-route 1/13 fails, comprehensive-e2e SOUL size failures. Routing layer HEALTHY (49/49). Action: Taoz trim main SOUL.md to <20K chars.','{"tags":"","status":"active","confidence":1.0}',1773115970000,'2026-03-10 04:12:50');
INSERT INTO vault VALUES(2761,'knowledge','digest-1773116000','','','session/argus/2026-03-10','argus','bug','done-gate infinite loop confirmed: dispatched ''Run regression testing for task: Run regression testing for task:...'' — same task re-dispatched within 4 minutes. Knowledge base shows 6+ instances. Fix: Taoz add recursion detection to done-gate to block nested regression dispatches.','{"tags":"","status":"active","confidence":1.0}',1773116000000,'2026-03-10 04:13:20');
INSERT INTO vault VALUES(2762,'knowledge','evomap-fix',NULL,'','operations/patterns','taoz','','EvoMap publish pipeline fixed: dynamic strategy from vault, publish_date nonce prevents 409 duplicates, expanded source_type query to include patterns+biz-opportunity+operational data','{}',1773133645,'2026-03-10 09:07:25');
INSERT INTO vault VALUES(2763,'knowledge','digest-1773137563','','','session/claude-code/2026-03-10','main,taoz,athena,hermes','critical-pattern','HALLUCINATION CASCADE: Agents trust each other''s memory without verification. Taoz built local files, marked success. Zenni read success, wrote ''Store live''. Athena wrote fake performance analysis. 2937 fake references across 97 files. FIX: Anti-hallucination rule — must curl/verify before marking done. Local files ≠ live products.','{"tags":"","status":"active","confidence":1.0}',1773137563000,'2026-03-10 10:12:43');
INSERT INTO vault VALUES(2764,'knowledge','digest-1773137567','','','session/claude-code/2026-03-10','taoz,dreami,iris,hermes','architecture','TWO-LAYER AGENT ARCHITECTURE: Brain (gpt-5.4 OpenClaw, dollar0 OAuth) THINKS/PLANS. Engine (Claude Code CLI Opus or Gemini CLI 3.1Pro, both dollar0) EXECUTES. Taoz→Claude Code. Dreami/Iris/Hermes→Gemini CLI. 8/9 agents on gpt-5.4. Only Myrmidons on minimax-m2.5 for cheap bulk ops.','{"tags":"","status":"active","confidence":1.0}',1773137567000,'2026-03-10 10:12:47');
INSERT INTO vault VALUES(2765,'knowledge','digest-1773137569','','','session/claude-code/2026-03-10','main','operations','MISSION-FIRST HEARTBEAT: Zenni was checking 7 system-maintenance steps before missions — drowning in status. Fix: ACTIVE-MISSION.md is Step 1 (80pct time). Maintenance demoted to Step 5 (only if idle). Anti-hallucination rule in SOUL.md: must verify with curl/proof before marking done.','{"tags":"","status":"active","confidence":1.0}',1773137569000,'2026-03-10 10:12:49');
INSERT INTO vault VALUES(2766,'knowledge','digest-1773141902','','','session/2026-03-10','main','session-learning','SOUL.md bloat kills execution — Zenni had 388 lines of rules. She spent time reading rules instead of executing. Fix: slim to 131 lines, move governance to on-demand skills. Pattern: agent identity files should be <150 lines; detailed protocols belong in skills loaded on-demand.','{"tags":"","status":"active","confidence":1.0}',1773141902000,'2026-03-10 11:25:02');
INSERT INTO vault VALUES(2767,'pattern','soul-md-slim','','','session/2026-03-10','main','observed','SOUL.md bloat kills execution — Zenni had 388 lines of rules. She spent time reading rules instead of executing. Fix: slim to 131 lines, move governance to on-demand skills. Pattern: agent identity files should be <150 lines; detailed protocols belong in skills loaded on-demand.','{"name":"soul-md-slim","occurrences":1,"status":"observed"}',1773141902000,'2026-03-10 11:25:02');
INSERT INTO vault VALUES(2768,'knowledge','digest-1773141906','','','session/2026-03-10','taoz','session-learning','CLI flag ordering causes silent failures — claude -p --add-dir DIR PROMPT silently swallows the prompt as a directory. The --add-dir flag must come BEFORE other flags, not right before the positional prompt argument. Every build since Mar 4 was broken (0 bytes) and nobody noticed for 6 days.','{"tags":"","status":"active","confidence":1.0}',1773141906000,'2026-03-10 11:25:06');
INSERT INTO vault VALUES(2769,'pattern','cli-flag-ordering','','','session/2026-03-10','taoz','observed','CLI flag ordering causes silent failures — claude -p --add-dir DIR PROMPT silently swallows the prompt as a directory. The --add-dir flag must come BEFORE other flags, not right before the positional prompt argument. Every build since Mar 4 was broken (0 bytes) and nobody noticed for 6 days.','{"name":"cli-flag-ordering","occurrences":1,"status":"observed"}',1773141906000,'2026-03-10 11:25:06');
INSERT INTO vault VALUES(2770,'knowledge','digest-1773141908','','','session/2026-03-10','main,taoz','session-learning','Duplicate cron entries cause gateway saturation — System crontab had 6 entries duplicating gateway-native cron jobs. Both competed for gateway sessions, causing 330s timeouts. Fix: disable system crontab duplicates, keep gateway-native crons only.','{"tags":"","status":"active","confidence":1.0}',1773141908000,'2026-03-10 11:25:08');
INSERT INTO vault VALUES(2771,'pattern','cron-dedup','','','session/2026-03-10','main,taoz','observed','Duplicate cron entries cause gateway saturation — System crontab had 6 entries duplicating gateway-native cron jobs. Both competed for gateway sessions, causing 330s timeouts. Fix: disable system crontab duplicates, keep gateway-native crons only.','{"name":"cron-dedup","occurrences":1,"status":"observed"}',1773141908000,'2026-03-10 11:25:08');
INSERT INTO vault VALUES(2772,'knowledge','digest-1773141911','','','session/2026-03-10','main,taoz','session-learning','Cron frequency matters — 15-minute crons with expensive models (glm-5) reading 66KB files saturated the gateway with overlapping sessions. Fix: 30-minute intervals with cheap models (glm-4.7-flash) and slimmed messages.','{"tags":"","status":"active","confidence":1.0}',1773141911000,'2026-03-10 11:25:11');
INSERT INTO vault VALUES(2773,'pattern','cron-frequency','','','session/2026-03-10','main,taoz','observed','Cron frequency matters — 15-minute crons with expensive models (glm-5) reading 66KB files saturated the gateway with overlapping sessions. Fix: 30-minute intervals with cheap models (glm-4.7-flash) and slimmed messages.','{"name":"cron-frequency","occurrences":1,"status":"observed"}',1773141911000,'2026-03-10 11:25:11');
INSERT INTO vault VALUES(2774,'knowledge','digest-1773141915','','','session/2026-03-10','main','workflow','Yang 3-department model for AI companies — Intelligence (Know: research+analysis), Marketing (Create+Sell: CMO+creative+visual), Operations (Build+Ship: CTO+QA+workers). Each department gets own workflow states. Tasks cascade via blocking relations.','{"tags":"","status":"active","confidence":1.0}',1773141915000,'2026-03-10 11:25:15');
