INSERT INTO vault VALUES(2776,'knowledge','digest-1773141918','','','session/2026-03-10','main,taoz,argus','workflow','Mistake-Learning-Lock pipeline — 4 stages: DETECT (mistake caught) → ANALYZE (root cause) → LOCK (rule in SOUL.md + protocol + regression test) → EVOLVE (EvoMap Gene+Capsule publish). Makes mistakes permanent learnings.','{"tags":"","status":"active","confidence":1.0}',1773141918000,'2026-03-10 11:25:18');
INSERT INTO vault VALUES(2777,'pattern','mistake-lock-pipeline','','','session/2026-03-10','main,taoz,argus','observed','Mistake-Learning-Lock pipeline — 4 stages: DETECT (mistake caught) → ANALYZE (root cause) → LOCK (rule in SOUL.md + protocol + regression test) → EVOLVE (EvoMap Gene+Capsule publish). Makes mistakes permanent learnings.','{"name":"mistake-lock-pipeline","occurrences":1,"status":"observed"}',1773141918000,'2026-03-10 11:25:18');
INSERT INTO vault VALUES(2778,'knowledge','digest-1773141920','','','session/2026-03-10','dreami,iris,hermes','workflow','File naming conventions for creative pipeline — campaigns at brands/{brand}/campaigns/{slug}/, raw/ for pre-prod, final/ for post-prod, copy/ for text. Images: {type}-{number}.{ext}. Finals: {platform}-{format}.{ext}.','{"tags":"","status":"active","confidence":1.0}',1773141920000,'2026-03-10 11:25:20');
INSERT INTO vault VALUES(2779,'pattern','file-naming-conventions','','','session/2026-03-10','dreami,iris,hermes','observed','File naming conventions for creative pipeline — campaigns at brands/{brand}/campaigns/{slug}/, raw/ for pre-prod, final/ for post-prod, copy/ for text. Images: {type}-{number}.{ext}. Finals: {platform}-{format}.{ext}.','{"name":"file-naming-conventions","occurrences":1,"status":"observed"}',1773141920000,'2026-03-10 11:25:20');
INSERT INTO vault VALUES(2780,'knowledge','digest-1773143208','','','session/argus/2026-03-10','argus','session-learning','Regression bridge test: Taoz connectivity passed but exact-instruction compliance failed. Prompt required exactly two short lines; Taoz appended explanatory text, so bridge is operational but strict format adherence is unreliable.','{"tags":"","status":"active","confidence":1.0}',1773143208000,'2026-03-10 11:46:49');
INSERT INTO vault VALUES(2781,'knowledge','dispatch-timeout-fix-1',NULL,'gaia-os','operations/dispatch','taoz','learning','multi-agent dispatch timeout caused by heartbeat-dispatch session collision — heartbeat consumes timeout window before dispatch task starts. Fix: increase timeout 300s→600s + priority override prefix to skip heartbeat on urgent dispatches.','{"tags": ["multi-agent", "orchestration", "timeout", "dispatch", "heartbeat"]}',1773150705514,'2026-03-10 13:51:45');
INSERT INTO vault VALUES(2782,'knowledge','dispatch-timeout-fix-2',NULL,'gaia-os','operations/dispatch','taoz','learning','Agent dispatch tasks must include explicit scope: exact input files, exact output path, single deliverable. Open-ended exploration dispatches timeout. Narrower scope = higher completion rate.','{"tags": ["multi-agent", "orchestration", "dispatch", "task-framing"]}',1773150713087,'2026-03-10 13:51:53');
INSERT INTO vault VALUES(2783,'knowledge','digest-1773150725','','','session/argus/2026-03-10','argus','session-learning','Creative Studio regression PASS: Taoz delivered a real file-backed foundation. Verified skill files exist, workflow JSON is valid with 4 stages, and studio.sh launch/status works end-to-end for a real mirra run. Note: when posting multiline room messages via shell, avoid raw backticks; use JSON serialization to prevent shell interpolation corruption.','{"tags":"","status":"active","confidence":1.0}',1773150725000,'2026-03-10 13:52:05');
INSERT INTO vault VALUES(2784,'knowledge','digest-1773151702','','','operations/learning-loop','taoz','session-learning','GAIA unified learning loop: scan_rooms→vault.db→evomap publish→fetch community→ingest. 4 daily cycles (08:30/13:00/18:30/23:00). Community capsules ingested to vault as source_type=community. Bidirectional: GAIA teaches the network AND learns from it.','{"tags":"evomap,learning-loop,compound,community","status":"active","confidence":1.0}',1773151702000,'2026-03-10 14:08:23');
INSERT INTO vault VALUES(2785,'knowledge','digest-1773196188','','','operations/session-management','taoz','pattern','Agent session files accumulate without pruning (606 sessions for main agent). Config says pruneAfter:7d but gateway doesn''t enforce it. Causes: context amnesia, hallucination repeats, memory bloat. Fix: manual cleanup + enforce pruning.','{"tags":"","status":"active","confidence":1.0}',1773196188000,'2026-03-11 02:29:48');
INSERT INTO vault VALUES(2786,'pattern','session-bloat-amnesia','','','operations/session-management','taoz','observed','Agent session files accumulate without pruning (606 sessions for main agent). Config says pruneAfter:7d but gateway doesn''t enforce it. Causes: context amnesia, hallucination repeats, memory bloat. Fix: manual cleanup + enforce pruning.','{"name":"session-bloat-amnesia","occurrences":1,"status":"observed"}',1773196188000,'2026-03-11 02:29:48');
INSERT INTO vault VALUES(2787,'knowledge','digest-1773196189','','','operations/knowledge-sync','taoz','session-learning','KNOWLEDGE-SYNC.md must exist at workspace-main/ (symlink to workspace-taoz/) because Zenni reads from her own workspace path. Missing file = silent failure, agents miss all learnings.','{"tags":"","status":"active","confidence":1.0}',1773196189000,'2026-03-11 02:29:49');
INSERT INTO vault VALUES(2788,'knowledge','digest-1773196190','','','operations/cron-management','taoz','pattern','Cron jobs get disabled over time but never removed from config. Causes: log spam, confusion, stale state tracking. Rule: delete disabled jobs immediately, don''t just set enabled:false.','{"tags":"","status":"active","confidence":1.0}',1773196190000,'2026-03-11 02:29:50');
INSERT INTO vault VALUES(2789,'pattern','cron-job-decay','','','operations/cron-management','taoz','observed','Cron jobs get disabled over time but never removed from config. Causes: log spam, confusion, stale state tracking. Rule: delete disabled jobs immediately, don''t just set enabled:false.','{"name":"cron-job-decay","occurrences":1,"status":"observed"}',1773196190000,'2026-03-11 02:29:50');
INSERT INTO vault VALUES(2790,'knowledge','digest-1773196191','','','operations/log-management','taoz','session-learning','Gateway logs grow unbounded (386MB gateway.err.log, 67MB fetcher.log). No log rotation configured. Fix: periodic truncation via cron or logrotate equivalent.','{"tags":"","status":"active","confidence":1.0}',1773196191000,'2026-03-11 02:29:51');
INSERT INTO vault VALUES(2791,'knowledge','digest-1773196192','','','operations/soul-management','taoz','pattern','SOUL.md files grow → exceed 20KB gateway limit → agent fails → emergency slim → rules forgotten → behavior degrades → grows again. Fix: enforce 150-line hard limit, move protocols to on-demand skills.','{"tags":"","status":"active","confidence":1.0}',1773196192000,'2026-03-11 02:29:52');
