INSERT INTO vault VALUES(2793,'knowledge','digest-1773196194','','','operations/verification','taoz','pattern','Anti-hallucination rules written in SOUL.md but not enforced mechanically. Agents still report done without curl/verify. Rule exists but has no enforcement mechanism. Need: blocking check that prevents done status without verification proof.','{"tags":"","status":"active","confidence":1.0}',1773196194000,'2026-03-11 02:29:54');
