INSERT INTO vault VALUES(2795,'knowledge','digest-1773196195','','','operations/gateway','taoz','pattern','Gateway binary can run older version than CLI. LaunchAgent plist points to /usr/local/lib/ (old) while CLI installs to ~/local/lib/ (new). After openclaw update: must restart gateway AND verify plist path matches.','{"tags":"","status":"active","confidence":1.0}',1773196195000,'2026-03-11 02:29:55');
INSERT INTO vault VALUES(2796,'pattern','gateway-version-mismatch','','','operations/gateway','taoz','observed','Gateway binary can run older version than CLI. LaunchAgent plist points to /usr/local/lib/ (old) while CLI installs to ~/local/lib/ (new). After openclaw update: must restart gateway AND verify plist path matches.','{"name":"gateway-version-mismatch","occurrences":1,"status":"observed"}',1773196195000,'2026-03-11 02:29:55');
INSERT INTO vault VALUES(2797,'knowledge','digest-1773196196','','','operations/updates','taoz','session-learning','OpenClaw 3.8 update introduced stricter channel validation - cron jobs with channel:webchat rejected when telegram+whatsapp configured. Updates can break working cron configs. Always test cron delivery after updates.','{"tags":"","status":"active","confidence":1.0}',1773196196000,'2026-03-11 02:29:56');
