INSERT INTO vault VALUES(2799,'pattern','relay-tier-overreach','','','operations/routing','taoz','observed','classify.sh CONVERSATIONAL pattern too broad - matches action phrases like ''start asap'', ''roll out'', ''look into''. Makes Zenni a chatbot instead of CEO. Fix: exclude action keywords from RELAY pattern, route to DISPATCH instead.','{"name":"relay-tier-overreach","occurrences":1,"status":"observed"}',1773196198000,'2026-03-11 02:29:58');
INSERT INTO vault VALUES(2800,'knowledge','digest-1773196199','','','operations/audit','taoz','session-learning','Full system audit checklist: (1) all log files for errors (2) cron job health (3) session counts per agent (4) config validation (5) file path integrity (6) symlink verification (7) version consistency (8) room file sizes (9) vault.db error patterns (10) memory file contradictions. Run monthly.','{"tags":"","status":"active","confidence":1.0}',1773196199000,'2026-03-11 02:29:59');
