INSERT INTO vault VALUES(2805,'knowledge','digest-1773229018','','','session/argus/2026-03-11','argus','session-learning','Verified Taoz''s P1 Chatwoot Lead Capture Activation. Implementation properly creates a workaround for WhatsApp Business API blocks via widget embed, fully isolating the lead capture within a new chatwoot-lead-capture directory with setup, env keys, and n8n webhook json configurations.','{"tags":"","status":"active","confidence":1.0}',1773229018000,'2026-03-11 11:36:58');
INSERT INTO vault VALUES(2806,'knowledge','digest-1773255918','','','session/argus/2026-03-12','argus','session-learning','Verified Taoz''s MIRRA Chatwoot attribution foundation audit. The right regression target here is the single promised planning artifact plus existence/consistency of referenced local MIRRA attribution files, not generic suite reruns. Existing local scaffolding is complete; remaining blockers are credential wiring and deployment access.','{"tags":"","status":"active","confidence":1.0}',1773255918000,'2026-03-11 19:05:18');
INSERT INTO vault VALUES(2807,'knowledge','digest-1773277692','','','session/argus/2026-03-12','argus','session-learning','MIRRA Chatwoot staging regression PASS when verified through local HTTP: FILL_ME guards prevented Chatwoot and Meta Pixel network loads, browser console stayed clean, and fbclid persistence worked; wa.me injection remained code-level only because order.html currently exposes no wa.me anchor to click.','{"tags":"","status":"active","confidence":1.0}',1773277692000,'2026-03-12 01:08:12');
INSERT INTO vault VALUES(2808,'knowledge','digest-1773290101','','','session/argus/2026-03-12','argus','session-learning','MIRRA handoff regression FAIL: when a script has already been inlined into a landing page, QA must reject any checklist that tells the operator to edit the source script instead of the live embedded file, because the activation instructions become false even if the code itself is staged correctly.','{"tags":"","status":"active","confidence":1.0}',1773290101000,'2026-03-12 04:35:01');
INSERT INTO vault VALUES(2809,'knowledge','digest-1773291825','','','session/argus/2026-03-12','argus','session-learning','MIRRA attribution-pipeline regression FAIL: for build tasks with explicit output paths, artifact existence at the exact requested path is a hard gate. A completion message without the file present is not sufficient for QA pass.','{"tags":"","status":"active","confidence":1.0}',1773291825000,'2026-03-12 05:03:45');
