/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE vault (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  source_type TEXT NOT NULL,     -- shared-facts, seeds, image-seeds, patterns, brand-dna, room-exec, room-feedback, memory, manual, document
  source_ref TEXT,               -- original ID or line number for citation
  source_path TEXT,              -- file path of origin
  brand TEXT DEFAULT '',         -- brand name (mirra, pinxin-vegan, etc.)
  category TEXT DEFAULT '',      -- taxonomy category (research/competitor, templates/winning, etc.)
  agent TEXT DEFAULT '',         -- which agent created/discovered this
  entry_type TEXT DEFAULT '',    -- learning, hook, copy, image, pattern, decision, failure, fact, etc.
  text TEXT NOT NULL,            -- the actual knowledge content
  metadata TEXT DEFAULT '{}',    -- JSON blob for extra fields (performance, tags, etc.)
  ts INTEGER DEFAULT 0,         -- timestamp (epoch ms)
  created_at TEXT DEFAULT (datetime('now'))
);
PRAGMA writable_schema=ON;
  text, brand, category, agent, entry_type,
  content=vault,
  content_rowid=id
)');
CREATE TABLE IF NOT EXISTS 'vault_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'vault_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'vault_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'vault_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TRIGGER vault_ai AFTER INSERT ON vault BEGIN
  VALUES (new.id, new.text, new.brand, new.category, new.agent, new.entry_type);
END;
CREATE TRIGGER vault_ad AFTER DELETE ON vault BEGIN
  VALUES ('delete', old.id, old.text, old.brand, old.category, old.agent, old.entry_type);
END;
CREATE TRIGGER vault_au AFTER UPDATE ON vault BEGIN
  VALUES ('delete', old.id, old.text, old.brand, old.category, old.agent, old.entry_type);
  VALUES (new.id, new.text, new.brand, new.category, new.agent, new.entry_type);
END;
PRAGMA writable_schema=OFF;
COMMIT;
